.entry { background: var(--panel); border: 1px solid var(--line); border-radius: 3px; padding: 13px 14px; margin-bottom: 11px; }
.entry-top { display: flex; justify-content: space-between; align-items: center; gap: 10px; margin-bottom: 9px; }
