/* ============================================================
   THE PREPAYMENT LEDGER — editorial financial-broadsheet system
   ============================================================ */
:root {
  --paper: #f4f0e6;
  --paper-raised: #fbf8f0;
  --panel: #efe9da;
  --ink: #191d26;
  --ink-soft: #565b66;
  --ink-faint: #8b8576;
  --line: #d7cfbc;
  --line-strong: #b9af98;

  --emerald: #1c7355;       /* money SAVED / kept */
  --emerald-bright: #2ba074;
  --emerald-wash: #e2ede4;
  --clay: #b0542f;          /* interest PAID / cost */
  --clay-wash: #f0e2d6;
  --gold: #b88a2a;

  --shadow: 0 1px 0 #fff inset, 0 18px 40px -28px rgba(25, 29, 38, 0.5);
  --display: "Fraunces", "Iowan Old Style", Georgia, "Times New Roman", serif;
  --body: "Hanken Grotesk", "Segoe UI", system-ui, sans-serif;
}

* { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; }

body {
  font-family: var(--body);
  color: var(--ink);
  background-color: var(--paper);
